parameters.command:
python3 - <<'PYEOF'
import xml.etree.ElementTree as ET

path = "/work/output/artifacts/skill-bpmn-integration-service-boundary/SlackDigestBoundaryBpmn/SlackDigestBoundaryBpmn.bpmn"
tree = ET.parse(path)
root = tree.getroot()

ns = {
    "bpmn":   "http://www.omg.org/spec/BPMN/20100524/MODEL",
    "bpmndi": "http://www.omg.org/spec/BPMN/20100524/DI",
    "dc":     "http://www.omg.org/spec/DD/20100524/DC",
    "di":     "http://www.omg.org/spec/DD/20100524/DI",
    "uipath": "http://uipath.org/schema/bpmn",
}

errors = []

# 1. Root is bpmn:definitions with correct namespaces
tag = root.tag
if "definitions" not in tag.lower():
    errors.append(f"Root is not definitions: {tag}")
else:
    print("CHECK 1: Root is definitions - OK")

# Collect all declared ids
all_ids = {el.get("id") for el in root.iter() if el.get("id")}
print(f"CHECK: All declared IDs: {sorted(all_ids)}")

# 2. BPMNDiagram exists with shapes and edges
diagrams = root.findall(".//bpmndi:BPMNDiagram", ns)
if not diagrams:
    errors.append("No BPMNDiagram found")
else:
    shapes = root.findall(".//bpmndi:BPMNShape", ns)
    edges  = root.findall(".//bpmndi:BPMNEdge", ns)
    shape_refs = {s.get("bpmnElement") for s in shapes}
    edge_refs  = {e.get("bpmnElement") for e in edges}
    print(f"CHECK 2: BPMNDiagram present, {len(shapes)} shapes, {len(edges)} edges - OK")
    print(f"  Shape bpmnElements: {sorted(shape_refs)}")
    print(f"  Edge bpmnElements:  {sorted(edge_refs)}")

# 3. All *Ref attributes resolve
process = root.find("bpmn:process", ns)
flow_nodes = {el.get("id") for el in process if el.get("id")}
for el in root.iter():
    for attr in ("sourceRef", "targetRef", "attachedToRef"):
        val = el.get(attr)
        if val and val not in all_ids:
            errors.append(f"Unresolved {attr}={val!r} on {el.get('id')!r}")

# Check incoming/outgoing references
flows = {sf.get("id") for sf in process.findall("bpmn:sequenceFlow", ns)}
for el in process.iter():
    for child in el:
        if "incoming" in child.tag or "outgoing" in child.tag:
            val = child.text.strip() if child.text else ""
            if val and val not in flows:
                errors.append(f"Incoming/outgoing ref {val!r} not in sequenceFlows")

print("CHECK 3: Ref resolution - OK" if not [e for e in errors if "Unresolved" in e or "not in" in e] else "CHECK 3: ERRORS")

# 4. No XOR gateways (none present, so this passes trivially)
gws = process.findall("bpmn:exclusiveGateway", ns)
print(f"CHECK 4: ExclusiveGateways: {len(gws)} (none required for this process) - OK")

# 5. No activity/event has more than one incoming flow
for el in process:
    inc = el.findall("bpmn:incoming", ns)
    if len(inc) > 1:
        errors.append(f"Element {el.get('id')} has {len(inc)} incoming flows (fake join)")

print("CHECK 5: No fake joins - OK")

# 6. Event subprocesses - none present
esubs = [el for el in process if el.get("triggeredByEvent") == "true"]
print(f"CHECK 6: Event subprocesses: {len(esubs)} - OK")

# 7. Variable references - check vars.* in CDATA bodies
import re
var_ids = set()
for vi in root.iter("{http://uipath.org/schema/bpmn}inputOutput"):
    vid = vi.get("id")
    if vid:
        var_ids.add(vid)
print(f"CHECK 7: Declared variable IDs: {sorted(var_ids)}")
bpmn_text = open(path).read()
var_refs = set(re.findall(r'vars\.(\w+)', bpmn_text))
for ref in var_refs:
    if ref not in var_ids:
        errors.append(f"Expression vars.{ref} references undeclared variable")
print(f"  Variable references in expressions: {sorted(var_refs)}")
missing = var_refs - var_ids
if missing:
    errors.append(f"Missing variable declarations: {missing}")
else:
    print("  All variable refs resolve - OK")

# 8. Diagram completeness: every process flow node has a BPMNShape
node_ids = {el.get("id") for el in process
            if el.get("id") and "sequenceFlow" not in el.tag and "extensionElements" not in el.tag}
for nid in node_ids:
    if nid not in shape_refs:
        errors.append(f"Node {nid!r} has no BPMNShape")
for fid in flows:
    if fid not in edge_refs:
        errors.append(f"SequenceFlow {fid!r} has no BPMNEdge")

if errors:
    print("\nERRORS:")
    for e in errors:
        print(f"  - {e}")
else:
    print("\nAll structural checks PASSED.")
PYEOF
